package com.hospital.management.validation;import com.hospital.management.model.AppointmentForm;import org.junit.jupiter.api.Test;import java.time.*;import static org.junit.jupiter.api.Assertions.*;
class AppointmentValidatorTest {private final AppointmentValidator v=new AppointmentValidator();private AppointmentForm valid(){AppointmentForm f=new AppointmentForm();f.setPatientId(1L);f.setDoctorId(2L);f.setAppointmentDate(LocalDate.now().plusDays(1).toString());f.setStartTime("09:00");f.setReason("Routine consultation");f.setNotes("");f.setStatus("SCHEDULED");return f;}@Test void validBooking(){assertFalse(v.validateBooking(valid()).hasErrors());}@Test void invalidPatientAndDoctor(){AppointmentForm f=valid();f.setPatientId(0L);f.setDoctorId(null);assertTrue(v.validateBooking(f).hasErrors());}@Test void pastDate(){AppointmentForm f=valid();f.setAppointmentDate(LocalDate.now().minusDays(1).toString());assertNotNull(v.validateBooking(f).getError("appointmentDate"));}@Test void todayPastSlot(){AppointmentForm f=valid();f.setAppointmentDate(LocalDate.now().toString());f.setStartTime(LocalTime.now().minusMinutes(5).withSecond(0).withNano(0).toString());assertNotNull(v.validateBooking(f).getError("startTime"));}@Test void invalidTimeAndShortReason(){AppointmentForm f=valid();f.setStartTime("25:10");f.setReason("x");ValidationResult r=v.validateBooking(f);assertNotNull(r.getError("startTime"));assertNotNull(r.getError("reason"));}@Test void longNotesAndInvalidStatus(){AppointmentForm f=valid();f.setNotes("x".repeat(1001));f.setStatus("UNKNOWN");ValidationResult r=v.validateBooking(f);assertNotNull(r.getError("notes"));assertNotNull(r.getError("status"));}}
